import { Question } from "./tara";

export const papers: Record<string, { title: string; source: string; questions: Question[] }> = {
  "tsa-2022-ct": {
    title: "Critical Thinking Practice",
    source: "TSA 2022",
    questions: [
      { displayNum: 1, tsaNum: 1, type: "Main Conclusion", text: "Which one of the following best expresses the main conclusion of the above argument?", correctAnswer: "A", options: [{letter:"A",text:"In the future gold will be prized for its practical uses rather than for its aesthetic appeal."},{letter:"B",text:"It wasn't until early in the last century that gold's electrical conductivity properties were discovered."},{letter:"C",text:"Gold is such an efficient conductor that it can carry tiny electrical currents and remain free of corrosion."},{letter:"D",text:"A small amount of gold is used in almost every modern electronic device."},{letter:"E",text:"Within ten years, more gold will be used in the production of electronics than in jewellery."}], hasWalkthrough: true,
        passage: "Throughout history, gold has been revered and used for expensive jewellery and ornamentation. But in the future, it will be prized for its practical uses rather than for its aesthetic appeal. It wasn't until early in the last century that gold's electrical conductivity properties were discovered. Solid state electronic devices use very low voltages and currents, which are easily interrupted by corrosion at the contact points. Gold is such an efficient conductor that it can carry these tiny currents and remain free of corrosion, making the devices highly reliable. A small amount of gold is used in almost every modern electronic device, and it is predicted that within ten years, more gold will be used in the production of electronics than in jewellery." },
      { displayNum: 2, tsaNum: 15, type: "Main Conclusion", text: "Which one of the following best expresses the main conclusion of the above argument?", correctAnswer: "C", options: [{letter:"A",text:"The word 'environment' does not apply only to the elements of air, earth, and water."},{letter:"B",text:"It is right to give prominent coverage to the damage human activity is doing to our bodies."},{letter:"C",text:"It is wrong to think that pollution of the air, earth and water is the only form of environmental damage."},{letter:"D",text:"The effects of artificial light and noise are physically and mentally harmful."},{letter:"E",text:"Many people are deprived of the sight of the stars or the experience of natural silence."}], hasWalkthrough: true,
        passage: "There is no denying the unwanted consequences of car emissions, burning of fossil fuels, chemical effluent, and other pollutants. Their negative effects include the increasing incidence of respiratory, skin, and heart conditions. But 'environments' consist of more than just the elements of air, earth, and water. Whilst it is quite right to headline the damage we are doing to our lungs and other bodily organs, it must not be thought that this is the only way in which we are polluting our world. The effects of artificial light and constant noise are also detrimental to mental and physical wellbeing. Many people, to their cost, rarely see the stars in the night sky, or experience the quiet of the natural environment in which our species evolved." },
      { displayNum: 3, tsaNum: 29, type: "Main Conclusion", text: "Which one of the following best expresses the main conclusion of the above argument?", correctAnswer: "B", options: [{letter:"A",text:"Progressive teaching methods put an emphasis on collaborative learning."},{letter:"B",text:"The idea that collaborative learning is best classroom practice needs to be reconsidered."},{letter:"C",text:"Collaborative learning appeals to extroverts, but much less so to those with introvert personalities."},{letter:"D",text:"Extroverts and introverts learn best in very different ways."},{letter:"E",text:"Over-emphasising fast-paced lessons and social learning undermines the learning of introverts."}], hasWalkthrough: true,
        passage: "'Progressive' teaching methods, used in schools for the last 40 or 50 years, put an emphasis on collaborative ways of learning. It is time to reconsider the idea that this constitutes best practice in the classroom. Collaborative learning appeals to those with extrovert personalities, but much less so to introverts. Extroverts are people with an outgoing or gregarious personality, who enjoy group projects and plenty of stimulation, whereas introverts prefer to work on their own and in a quiet place. Modern classroom environments embrace extroverted behaviour, through fast-paced lessons and social learning activities. These can foster an appealing classroom environment, of course, but over-emphasising them can undermine the learning of students who are inward-thinking and easily drained by constant interactions with others." },
      { displayNum: 4, tsaNum: 39, type: "Main Conclusion", text: "Which one of the following best expresses the main conclusion of the above argument?", correctAnswer: "C", options: [{letter:"A",text:"If someone accidentally kills someone while trying to rescue them we don't consider them a murderer."},{letter:"B",text:"We believe that judgements about the morality of an action should be based on the intention behind it."},{letter:"C",text:"Despite what we may like to think, our moral judgements can be influenced by luck."},{letter:"D",text:"The only difference between the two drivers is that the first driver got lucky."},{letter:"E",text:"The second driver did not intend to kill someone any more than the first did."}], hasWalkthrough: true,
        passage: "If someone tries to rescue someone from a burning roof, slips, drops them, and they die, we don't class them as a murderer. This is because we believe that judgements should be based on the intention behind an action, not the outcome. Whether or not we like to admit it, however, our moral judgements are sometimes shaped by mere luck. Imagine someone gets into a car while drunk and drives home. We all agree that's bad. Now imagine another person who does the same, but this person kills a pedestrian. We naturally think that this action is worse. But surely the only difference is that the first driver got lucky, while the second driver was unlucky. The second driver did not intend to kill a pedestrian any more than the first did." },
      { displayNum: 5, tsaNum: 47, type: "Main Conclusion", text: "Which one of the following best expresses the main conclusion of the above argument?", correctAnswer: "B", options: [{letter:"A",text:"Planners cannot foresee how cities will need to develop in response to various factors."},{letter:"B",text:"We lose something important if we over-plan and over-manage our cities."},{letter:"C",text:"The concept of the city as a pre-engineered machine works against important quality-of-life considerations."},{letter:"D",text:"Urban dwellers value community cohesion and other quality-of-life features as much as or even more than efficiency."},{letter:"E",text:"Community cohesion and other quality-of-life features require openness, freedom of choice, and the opposite of central control in order to blossom."}], hasWalkthrough: true,
        passage: "One vision dominating much of urban planning worldwide is that of the 'smart city', whereby urban areas are pre-planned and designed to be managed via digital technology with efficiency prioritised as the top objective. But planners cannot foresee how cities will need to develop depending on cultural trends, changes in economic sectors, and other factors. We lose something important if we over-plan and over-manage our cities. The concept of the city as a pre-engineered machine works against critically important quality-of-life considerations. Once basic services, like transport, are in place, urban dwellers value community cohesion, opportunities for self-expression, and other quality-of-life features as much as or even more than efficiency. Such elements require openness, freedom of choice, and the opposite of central control in order to blossom." },
      { displayNum: 6, tsaNum: 3, type: "Assumption", text: "Which one of the following is an underlying assumption of the above argument?", correctAnswer: "E", options: [{letter:"A",text:"Women in many countries do less shopping than in previous decades."},{letter:"B",text:"The decline in central shopping districts is happening more quickly in places with wealthier populations."},{letter:"C",text:"It is difficult for governments to try to stop the decline of central shopping areas."},{letter:"D",text:"The growth in online shopping will not threaten the profitability of large supermarkets on the outskirts of towns."},{letter:"E",text:"Traditional shopping areas serve no important purpose that cannot be satisfied by alternative shopping methods."}], hasWalkthrough: true,
        passage: "Whether known as the high street, main street, or market square, central shopping districts in many towns throughout the world are in danger of disappearing. The decline in some downtown shopping areas began decades ago because of various social and economic trends, including an increase in the number of women working outside of the home and the development of large supermarkets and retail parks further out on the outskirts of towns. While change is inevitably difficult, communities should not be fearful about the loss of their traditional shopping areas. Shopping is increasingly conducted via the internet. Compared to traditional ways of shopping, the online model offers savings in terms of time and other resources while also providing greater consumer choice." },
      { displayNum: 7, tsaNum: 22, type: "Assumption", text: "Which one of the following is an underlying assumption of the argument above?", correctAnswer: "D", options: [{letter:"A",text:"A reporter of the same racial background as the MPs would not have made this type of mistake."},{letter:"B",text:"Mistakes like the ones identified in the passage are common in the media."},{letter:"C",text:"Media organisations have a moral duty to ensure they have a diverse workforce."},{letter:"D",text:"Having a more diverse workforce enables mistakes like these to be avoided."},{letter:"E",text:"Similar types of errors do not take place in any other workplace."}], hasWalkthrough: true,
        passage: "In a recent UK news broadcast, a white reporter appeared to mistake a Labour Member of Parliament (MP), who is Black, for another MP who is also Black. This shows the dangers of a lack of diversity in workplaces. It is not the first time that such a mistake has occurred: a week earlier the same television channel had mistakenly shown footage of LeBron James in their coverage of the death of his fellow basketball star Kobe Bryant. A recent report showed that only 14.8% of that television channel's workforce were from a minority ethnic or racial background. Media organisations in the UK should take this as a wake-up call, and take steps to ensure that the diversity of their workforce mirrors that of the wider population." },
      { displayNum: 8, tsaNum: 33, type: "Assumption", text: "Which one of the following is an underlying assumption of the above argument?", correctAnswer: "C", options: [{letter:"A",text:"There is no need for larger cities in the north of England to have quicker links to the south."},{letter:"B",text:"Improving transport links is the method by which regional inequality has to be addressed."},{letter:"C",text:"The benefits to large cities are not sufficient to justify the project."},{letter:"D",text:"The level of regional inequality in the country is a problem that needs to be solved."},{letter:"E",text:"People generally do not enjoy a lengthy commute to work."}], hasWalkthrough: true,
        passage: "The UK has one of the world's highest levels of regional inequality, according to a recent report. Of the 30 nations studied, only 2 had higher levels of inequality. The main disparity is between those living in the poorer north and the wealthier south of the country. To address this, the government has been working on a large infrastructure project, HS2, which will improve transport links between cities in the north and south. However, the report warns that this project will only benefit the large cities, as journey times to areas outside those cities will continue to be affected by poor local transport infrastructure. The project will do nothing to benefit those living in smaller towns and villages in the north of the country, and so should be suspended immediately." },
      { displayNum: 9, tsaNum: 41, type: "Assumption", text: "Which one of the following is an underlying assumption of the above argument?", correctAnswer: "C", options: [{letter:"A",text:"There is no shortage of accessible means by which voters can gain relevant information about candidates."},{letter:"B",text:"Media companies have a financial interest in promoting televised debates."},{letter:"C",text:"Social skills are not a good indicator of leadership potential."},{letter:"D",text:"The televised debates encourage voters to rely on gender and other stereotypes when evaluating candidates."},{letter:"E",text:"Some high-quality candidates are discouraged from entering elections because of the emphasis on televised debates."}], hasWalkthrough: true,
        passage: "In recent years, televised debates between political candidates have taken on increasing significance in the elections held in various countries. Meant to encourage public participation in elections and help voters evaluate the candidates seeking their support, these events are not much more than noisy distractions. Rather than revealing more about positions and policies on important political issues, the debates put the spotlight squarely on candidates' social skills. Accordingly, media coverage of the debates tends to focus on how well candidates engage with one another, those asking the questions, and any audience members in attendance. But showcasing the ability – or inability – of candidates to demonstrate a desirable balance between being assertive and cooperative does little to help voters understand the leadership potential of those taking part." },
      { displayNum: 10, tsaNum: 27, type: "Reasoning Error", text: "Which one of the following best illustrates the flaw in the above argument?", correctAnswer: "B", options: [{letter:"A",text:"It draws a conclusion about what will happen from something that may or may not happen."},{letter:"B",text:"It assumes that there are no other reasons why a rail franchise might be lost."},{letter:"C",text:"It predicts what will happen in the future on the basis of what has happened to date."},{letter:"D",text:"It denies the possibility that the company may exceed the limits and still keep the franchise."},{letter:"E",text:"It concludes that the franchise will be kept but not that the fine will be avoided."}], hasWalkthrough: true,
        passage: "Trains in the UK are operated by private companies approved by the government and awarded a franchise for which they must meet certain standards, for example on punctuality. SuperRail, which operates the trains in one part of the country, has a poor record to date and has been warned that if it again exceeds the annual limits set by the government for late departures or arrivals, it will receive a heavy fine and will lose its franchise. At the end of the third quarter, however, SuperRail's performance was within the defined limits. So if the operator can maintain their performance in the final quarter, they will keep the franchise for another year." },
      { displayNum: 11, tsaNum: 40, type: "Reasoning Error", text: "Which one of the following best illustrates the flaw in the above argument?", correctAnswer: "D", options: [{letter:"A",text:"Just because people are household names, it does not mean they have the relevant expertise, or that their views are worth taking seriously."},{letter:"B",text:"It relies on the views of people who are likely to be biased in relation to AI."},{letter:"C",text:"It fails to consider whether the development of AI is indeed a genuine possibility."},{letter:"D",text:"The fact that both sides in the dispute can't be right doesn't mean that neither of them is."},{letter:"E",text:"It does not state what the rules around AI should actually be."}], hasWalkthrough: true,
        passage: "Should we be worried about Artificial Intelligence (AI)? On the one hand, there are big names that have expressed major concern. Elon Musk, Bill Gates and Stephen Hawking have all argued that AI poses the single biggest threat to mankind's existence. At the same time there are people such as Mark Zuckerberg (Facebook CEO) and leading AI researcher Andrew Ng, who reject this view as scaremongering, and insist that the risks behind AI can be eliminated by following a few simple rules. Clearly they cannot both be right, meaning that the truth must lie somewhere in the middle: AI cannot be without risks, but nor can it be the apocalyptic threat some say it is." },
      { displayNum: 12, tsaNum: 5, type: "Matching Arguments", text: "Which one of the following most closely parallels the reasoning used in the above argument?", correctAnswer: "E", options: [{letter:"A",text:"You are only promoted to be head teacher if you have taught for many years. You have taught for many years, so you are sure to be promoted to be head teacher."},{letter:"B",text:"You can only go to the concert if you buy tickets or win them in the competition. You must have bought your tickets as someone else won the competition."},{letter:"C",text:"You only get a high-paying job if you study hard in school. You are certain to get a high-paying job because you studied hard in school."},{letter:"D",text:"You can only apply for a loan from the bank or the credit union. You missed the bank's deadline for submitting forms, so you will have to apply to the credit union."},{letter:"E",text:"You are only eligible for the scholarship if you can prove financial need. You have been declared eligible for the scholarship so you must have proved financial need."}], hasWalkthrough: true,
        passage: "You only win an election if you gain a majority of votes. You must have gained a majority of votes because you were named the winner in the election." },
      { displayNum: 13, tsaNum: 21, type: "Matching Arguments", text: "Which one of the following most closely parallels the reasoning used in the above argument?", correctAnswer: "D", options: [{letter:"A",text:"Some experts believe that putting bath salts in the bath increases the likelihood of someone getting eczema. Charlie has eczema. It is likely he puts bath salts in his bath."},{letter:"B",text:"Most superheroes have super powers which help them fight villains. Batman doesn't have any super powers. Therefore he is not a superhero."},{letter:"C",text:"Frogs do not survive in ponds with duck weed. Mustafa has a pond in his garden with frogs living in it. It is possible that Mustafa's pond has frogs and no duck weed."},{letter:"D",text:"It is possible to get lung cancer without ever being a smoker. Jill has got lung cancer. Therefore, she may not be a smoker."},{letter:"E",text:"Some trees can be killed by hammering iron nails into them. Oswald's tree died. Therefore, he must have hammered an iron nail into it."}], hasWalkthrough: true,
        passage: "Some people have such good natural stamina that they can run a marathon with no training. John was able to run a marathon on Saturday. It is possible he did no training in preparation." },
      { displayNum: 14, tsaNum: 28, type: "Matching Arguments", text: "Which one of the following most closely parallels the reasoning used in the above argument?", correctAnswer: "A", options: [{letter:"A",text:"If you turn up the volume, the music gets louder. The music is very loud now which means that you turned up the volume."},{letter:"B",text:"If a company wants to be successful, it needs to insist on the punctuality of its employees. This company does not take the punctuality of its employees seriously, so it will not be successful."},{letter:"C",text:"Disciplinary action is initiated against all workers who do not wear a helmet on the building site. No disciplinary action has been initiated against Mike, so he must have always worn a helmet on the site."},{letter:"D",text:"You need a membership card to use the services of the gym. You do not have a membership card, so you cannot use the gym."},{letter:"E",text:"In order to anger a hippo, it is enough to drive close to it with a boat. They are driving close to this one, thus it will become angry."}], hasWalkthrough: true,
        passage: "If you arrive late for work, you will definitely get fired. You lost your last job so you must have arrived late for work." },
      { displayNum: 15, tsaNum: 45, type: "Matching Arguments", text: "Which one of the following most closely parallels the reasoning used in the above argument?", correctAnswer: "B", options: [{letter:"A",text:"If everyone who found themselves in the same position as Zach behaved the same way that he did, then we would be in an absolutely terrible situation. Fortunately for us, not everyone does behave in that way."},{letter:"B",text:"The volume of waste they generate shows that most coffee companies do not care about the environmental impact of their businesses. If they did, they wouldn't serve coffee in disposable cups."},{letter:"C",text:"If Bella really wanted to come to the party, then she would have told Anne. Unfortunately, since we are unable to contact Anne, we can't know if Bella really wanted to come."},{letter:"D",text:"If Einstein's theory of relativity is correct, then we would expect light rays from distant stars to bend as they pass our own star. The fact that we are able to observe this suggests Einstein's theory is correct."},{letter:"E",text:"No one who saw the game on Saturday would have thought it was between two sides at the very bottom of the league. If you'd seen the game, you would have agreed that the standard of football was impressively high."}], hasWalkthrough: true,
        passage: "If he was telling the truth about the incident, then we would not expect him to look so nervous talking to the police. The fact that he looks so nervous suggests he is probably lying." },
      { displayNum: 16, tsaNum: 11, type: "Drawing a Conclusion", text: "Which one of the following can be drawn as a conclusion from the above passage?", correctAnswer: "A", options: [{letter:"A",text:"We can expect some cities to expand beyond their current limits as a result of driverless cars."},{letter:"B",text:"There will no longer be any limits to suburban spread with the introduction of driverless cars."},{letter:"C",text:"The attractions of living in city centres will disappear once people have access to a driverless car."},{letter:"D",text:"The introduction of driverless cars could mean that there are no longer any green spaces for people to enjoy."},{letter:"E",text:"There will be more people living in suburban environments than city centres after the introduction of driverless cars."}], hasWalkthrough: true,
        passage: "People are attracted to cities because of the job opportunities that they bring. At the same time, house prices tend to push people away from urban centres. The draw of healthy living and green environments similarly pulls people towards less urban environments, further from city centres. The limiting factor in suburban spread – the expansion of cities beyond their existing boundaries – is often travel time, by either public or private means. One of the appeals of driverless cars is that they are set to cut delays by up to 40 per cent because they switch lanes more efficiently, drive closer to the vehicle in front, and travel at a constant speed without repeatedly braking and accelerating, which is the main cause of congestion." },
      { displayNum: 17, tsaNum: 35, type: "Drawing a Conclusion", text: "Which one of the following can be drawn as a conclusion from the above passage?", correctAnswer: "D", options: [{letter:"A",text:"It is always a good idea to help other people out if you possibly can."},{letter:"B",text:"How much a person likes another person is less of a motivating factor in human behaviour than psychologists had supposed."},{letter:"C",text:"Reciprocity is the most important motivation behind human behaviour."},{letter:"D",text:"People who help others out are more likely to end up better rewarded than people who don't."},{letter:"E",text:"A person who does not receive help from someone will feel no obligation to offer help in return."}], hasWalkthrough: true,
        passage: "It is no surprise to hear that we are more likely to help someone we like than someone we don't. But another factor that influences our behaviour towards others is a sense of reciprocity – the sense that you ought to do something good for someone if they have done something good for you. Psychologists have measured the effect of how much someone (Person 1) likes another person (Person 2) on the extent to which Person 1 will help Person 2 out. While there is a clear correlation here, it fades away in situations where Person 2 had previously done Person 1 a favour. In these cases, Person 1 consistently helps Person 2 out equally, regardless of how much they like them." },
      { displayNum: 18, tsaNum: 9, type: "Applying Principles", text: "Which one of the following best illustrates the principle used in the above argument?", correctAnswer: "C", options: [{letter:"A",text:"Skiers injured whilst skiing off the official ski run should be entitled to compensation from the manufacturer of the skis."},{letter:"B",text:"A passenger on a train who is injured tripping over luggage not put in the luggage rack should be entitled to compensation from the train company."},{letter:"C",text:"A child injured while playing on a broken swing in a park should be entitled to compensation from the park owner."},{letter:"D",text:"A householder scalded when pouring water from a kettle should be entitled to compensation from the manufacturer of the kettle."},{letter:"E",text:"People who eat too many biscuits and damage their health should be entitled to compensation from the shops which sold the biscuits."}], hasWalkthrough: true,
        passage: "Bicycle owners have a duty to have their bicycles maintained properly. This is to ensure the safety both of the rider and of other road users. If an injury is caused to another person as a result of a failure to maintain a bicycle properly, then the injured person should be entitled to compensation from the owner of the bicycle." },
      { displayNum: 19, tsaNum: 17, type: "Applying Principles", text: "Which one of the following best illustrates the principle used in the above argument?", correctAnswer: "D", options: [{letter:"A",text:"A person who is offered a free printer as a bonus when buying a new computer cannot complain if the computer is expensive."},{letter:"B",text:"A person who gives as gifts items obtained for free cannot complain if friends and family criticise them for being selfish."},{letter:"C",text:"A person who finds a winning lottery ticket cannot complain if the owner of the ticket tries to claim the winnings."},{letter:"D",text:"A person who obtains free legal advice online cannot complain if the advice ends up being unhelpful."},{letter:"E",text:"A person who buys an illegally copied film cannot complain if the picture is not as clear as they would like it to be."}], hasWalkthrough: true,
        passage: "People complain about the fact that newspapers are often full of recycled articles about celebrity gossip, but they forget that real news costs money – investigative reporters need to go out into the world and unearth new information. The trouble is, those who complain are also unprepared to pay to read newspapers, expecting to get information for free online. But what can people expect if they want to be able to read the news for free? As they say, you get what you pay for." },
      { displayNum: 20, tsaNum: 34, type: "Applying Principles", text: "Which one of the following best illustrates the principle used in the above argument?", correctAnswer: "D", options: [{letter:"A",text:"A person who fails to carry out a friend's dying wishes because they feel there is something morally wrong in the request has nevertheless failed to fulfil their moral duty."},{letter:"B",text:"A person who drives dangerously without considering the dangers and ends up hurting someone else is morally blameworthy even if they had no intention to do so."},{letter:"C",text:"A person who rejoices when a colleague goes through a hard time at work is still behaving badly, even if that person had previously caused them harm."},{letter:"D",text:"A person who upsets someone else by criticising their appearance cannot simply defend their action on grounds of freedom of speech."},{letter:"E",text:"A person who listens to their heart rather than their head when faced with a personal dilemma will not make the right decision."}], hasWalkthrough: true,
        passage: "A right is not an excuse. The fact that you have a right to do something cannot count as justification for doing it. I may have a right to walk along behind someone in the street, mimicking their walk. Does that mean I ought to go around doing this? In fact, when deciding how to act, it isn't really rights we should be turning to in order to guide our decisions, but morals. You should not be asking: do I have a right to do this? Instead you should be asking: is it right that I should do this?" },
      { displayNum: 21, tsaNum: 10, type: "Weaken", text: "Which one of the following, if true, most weakens the above argument?", correctAnswer: "D", options: [{letter:"A",text:"Swedish women do fewer hours of housework a week on average than women in many other countries."},{letter:"B",text:"Many women enjoy doing housework."},{letter:"C",text:"Sweden has a long-standing policy of paid paternity leave for fathers of newborn children."},{letter:"D",text:"Most of the cleaners hired because of the subsidy are women."},{letter:"E",text:"The Swedish educational system has a long tradition of emphasising gender-neutral teaching methods."}], hasWalkthrough: true,
        passage: "Despite ranking top of gender equality lists, Sweden is like practically every other country in terms of having an unequal division of labour for unpaid housework. Perpetuating stereotypes about who should be responsible for cleaning tasks, women still perform more domestic chores than their male partners. To address this enduring sexism about 'women's work', Sweden has recently implemented a tax policy through which the government pays half of the bill when households employ a cleaner. This policy has been a success: couples that hired a cleaner because of the subsidy report fewer arguments over housework, and the female partners have been able to devote a significant number of additional hours per month to their own paid employment." },
      { displayNum: 22, tsaNum: 23, type: "Weaken", text: "Which one of the following, if true, most weakens the above argument?", correctAnswer: "E", options: [{letter:"A",text:"Some students with SEND have problems with reading and writing but have good ability to understand and reason."},{letter:"B",text:"Some students with SEND require a quiet environment to help them to concentrate on what they are doing."},{letter:"C",text:"Some students with SEND require content and tasks from lessons to be explained to them in simpler language."},{letter:"D",text:"Some students with SEND have physical problems which require the provision of a wheelchair or other aids."},{letter:"E",text:"Some students with SEND have conditions which limit their ability to understand and to reason."}], hasWalkthrough: true,
        passage: "Recent figures issued by the UK Department of Education have revealed that the proportion of students with special educational needs and disabilities (SEND) who have reached the expected level of educational achievement by the time they leave secondary school is lower than that of the population as a whole. The Government cannot evade responsibility for this disappointing statistic. By not providing the funds required by schools who have students with these needs, the Government has failed to ensure the right of such students to equality of opportunity." },
      { displayNum: 23, tsaNum: 49, type: "Weaken", text: "Which one of the following, if true, most weakens the above argument?", correctAnswer: "B", options: [{letter:"A",text:"BBC presenters make up a small proportion of all people invited to speak at events."},{letter:"B",text:"Many MPs were established public figures before they entered Parliament."},{letter:"C",text:"Many MPs have second or third jobs outside Parliament."},{letter:"D",text:"Invitations to BBC presenters to speak at public events do not continue once the presenter has left the BBC."},{letter:"E",text:"The BBC issues clear guidelines to its employees about the types of events that they are allowed to speak at."}], hasWalkthrough: true,
        passage: "The government has recently announced that the method by which the British Broadcasting Corporation (BBC) is funded will be changed, leading to speculation that public funding for the organisation could soon be withdrawn. One of the complaints is that BBC TV and radio presenters \"make their profile at public expense\", but then earn income on top of their salaries by charging to speak at events to which they are invited purely due to their association with the BBC. However, figures show that, over the last five years, Members of Parliament (MPs) received £8.4m on top of their salaries through similar activities. Until MPs can behave in a way that is consistent with their criticisms of others, this policy to change the funding of the BBC should be scrapped." },
    ],
  },
  "tsa-2022-ps": {
    title: "Problem Solving Practice",
    source: "TSA 2022",
    questions: [
      { displayNum: 1, tsaNum: 2, type: "Problem Solving", text: "Which round did the winning team choose to have the score tripled?", correctAnswer: "B", hasWalkthrough: true, figureKey: "tsa-q2",
        options: [{letter:"A",text:"round 2"},{letter:"B",text:"round 3"},{letter:"C",text:"round 4"},{letter:"D",text:"round 5"},{letter:"E",text:"round 6"}],
        passage: "A quiz consists of 7 rounds, each of which contains 20 questions. Each question is worth one point. At the end of the quiz, but before any of the answers or scores are revealed, each team is allowed to select one of the rounds and the score for that round is tripled. In addition, the scores for the rounds immediately before and after the chosen round are doubled. The winning team at last week's quiz had the following scores in each of the rounds. The winning team's final score was 136." },
      { displayNum: 2, tsaNum: 6, type: "Problem Solving", text: "How much of mixture 2 does Rob need to use?", correctAnswer: "B", hasWalkthrough: true, figureKey: "tsa-q6",
        options: [{letter:"A",text:"1 litre"},{letter:"B",text:"2 litres"},{letter:"C",text:"3 litres"},{letter:"D",text:"4 litres"},{letter:"E",text:"5 litres"}],
        passage: "Rob has two different mixtures of apple juice and orange juice. Rob wants to use these two mixtures to make 6 litres of a juice mixture which is 50% apple juice and 50% orange juice." },
      { displayNum: 3, tsaNum: 7, type: "Problem Solving", text: "Fran is a lecturer and regularly needs to contact all of the departments in the university. How many of the extension numbers are never needed by Fran?", correctAnswer: "C", hasWalkthrough: true, figureKey: "tsa-q7",
        options: [{letter:"A",text:"0"},{letter:"B",text:"1"},{letter:"C",text:"2"},{letter:"D",text:"3"},{letter:"E",text:"4"}],
        passage: "The extension numbers needed to contact eight different departments in a university depend on whether the caller is calling as a student, parent, lecturer, journalist or researcher. The appropriate numbers are shown below." },
      { displayNum: 4, tsaNum: 8, type: "Problem Solving", text: "Which graph shows the information in the table above?", correctAnswer: "B", hasWalkthrough: true, figureKey: "tsa-q8",
        options: [{letter:"A",text:"Graph A"},{letter:"B",text:"Graph B"},{letter:"C",text:"Graph C"},{letter:"D",text:"Graph D"},{letter:"E",text:"Graph E"}],
        passage: "Over the past decade the popularity of coffee has soared in the United Kingdom. As a result, the number of coffee shops across the UK has risen. The table below shows a breakdown of the number of chain and independent coffee shops in East London between 2013 and 2019." },
      { displayNum: 5, tsaNum: 12, type: "Problem Solving", text: "Based upon my experience, by how many pence per day is my normal shampoo better value than the new brand?", correctAnswer: "A", hasWalkthrough: true,
        options: [{letter:"A",text:"1.5"},{letter:"B",text:"2.4"},{letter:"C",text:"4.9"},{letter:"D",text:"6.4"},{letter:"E",text:"9.5"}],
        passage: "The shampoo that I normally buy costs £1.96 for a 500ml bottle and always lasts for 40 days. Last month I decided to try a new brand that is 36p cheaper and contains 550 ml. However, because of the amount that I have had to use to wash my hair properly, it has run out after only 25 days." },
      { displayNum: 6, tsaNum: 13, type: "Problem Solving", text: "Which cottage will Kate and Tek choose?", correctAnswer: "B", hasWalkthrough: true, figureKey: "tsa-q13",
        options: [{letter:"A",text:"Acorns"},{letter:"B",text:"Beeches"},{letter:"C",text:"Chestnuts"},{letter:"D",text:"Denders"},{letter:"E",text:"Eglers"}],
        passage: "Kate and Tek are choosing a cottage to rent for their family holiday. They have searched online and reduced their choice to five cottages. The facilities offered by these cottages are shown in the following table. Ideally, Kate and Tek would like a cottage with at least three bedrooms, a large garden, wifi, parking, and they would like to be within 3 km of a store. They realise that it is unlikely that all their wishes will be met, so they decide to compromise. They insist that the cottage must have at least three bedrooms, but they will be happy if at least three of their other wishes are satisfied. If more than one cottage is suitable, then they will choose the one that is the cheapest to rent." },
      { displayNum: 7, tsaNum: 14, type: "Problem Solving", text: "What is the value of the word ANNA?", correctAnswer: "C", hasWalkthrough: true, figureKey: "tsa-q14",
        options: [{letter:"A",text:"4"},{letter:"B",text:"6"},{letter:"C",text:"8"},{letter:"D",text:"10"},{letter:"E",text:"12"}],
        passage: "Alex and Anita play a game where they need to form words from letters. The value of each letter is a whole number of points (which can be 0). Alex and Anita earn points by adding together the value of the letters in the words they form. The value of the last three words they formed is shown in the table below. Anita has just formed the word ANNA." },
      { displayNum: 8, tsaNum: 18, type: "Problem Solving", text: "How much money will Sean save by taking the cheaper option?", correctAnswer: "D", hasWalkthrough: true,
        options: [{letter:"A",text:"$13"},{letter:"B",text:"$20"},{letter:"C",text:"$30"},{letter:"D",text:"$70"},{letter:"E",text:"$127"}],
        passage: "Sean is taking his car to Sunny Island. He lives 38 miles away from the mainland terminal where the seaport and airport are based. He has researched the travel costs and come up with two possible options. The ferry ticket (car and passenger) is $80. Alternatively, a plane ticket is $50 and the seaport company will transport his car (port to port) for $100. Fuel costs are $1.50 per mile." },
      { displayNum: 9, tsaNum: 19, type: "Problem Solving", text: "Fay wants to swap her Tuesday duty with one of the others to be on duty on Monday or Thursday instead. Who is the only volunteer on the rota for Monday or Thursday that Fay could swap with if the conditions are still to be met?", correctAnswer: "B", hasWalkthrough: true, figureKey: "tsa-q19",
        options: [{letter:"A",text:"Mel"},{letter:"B",text:"Pat"},{letter:"C",text:"Rod"},{letter:"D",text:"Sam"},{letter:"E",text:"Tim"}],
        passage: "A youth club is open six evenings every week. There are nine volunteers who run the club. Each evening three of the volunteers are on duty. When the rota is drawn up for any week, the following conditions must be met: Each volunteer has two evenings of duty, but never two consecutive evenings. No two volunteers are on duty together twice in the same week. Next week's rota has just been published:" },
      { displayNum: 10, tsaNum: 20, type: "Problem Solving", text: "Which student has a mark that is incorrectly plotted on the scatter graph?", correctAnswer: "B", hasWalkthrough: true, figureKey: "tsa-q20",
        options: [{letter:"A",text:"Ffion"},{letter:"B",text:"Gary"},{letter:"C",text:"Huw"},{letter:"D",text:"Ken"},{letter:"E",text:"Mei"}],
        passage: "Students studying geography at college were tested at the start of the year and at the end of the year. Their marks are shown in the following table. The scatter graph below shows the marks for the 12 students, but one of the points has been incorrectly plotted." },
      { displayNum: 11, tsaNum: 24, type: "Problem Solving", text: "If each girl ran at a constant speed throughout the race, and Iman's speed was 25% faster than Maya's, for how many seconds did Iman run?", correctAnswer: "C", hasWalkthrough: true,
        options: [{letter:"A",text:"15 seconds"},{letter:"B",text:"18 seconds"},{letter:"C",text:"20 seconds"},{letter:"D",text:"22 seconds"},{letter:"E",text:"25 seconds"}],
        passage: "Iman and Maya ran a 100 metre race. Iman started 2 seconds after Maya and finished 3 seconds before her." },
      { displayNum: 12, tsaNum: 25, type: "Problem Solving", text: "Ester wants to buy the fishcakes that contain the greatest amount of fish per pound spent. Which make of fishcake should Ester buy?", correctAnswer: "D", hasWalkthrough: true, figureKey: "tsa-q25",
        options: [{letter:"A",text:"Arctic"},{letter:"B",text:"Banquet"},{letter:"C",text:"Chilco"},{letter:"D",text:"Dyner"},{letter:"E",text:"Evertop"}],
        passage: "Five popular makes of fishcake are shown in the table below, with comparisons of their ingredients, the weight of each type and the cost for a pack of two." },
      { displayNum: 13, tsaNum: 26, type: "Problem Solving", text: "What is the difference between the highest and lowest average salaries of politicians in the countries listed above?", correctAnswer: "E", hasWalkthrough: true, figureKey: "tsa-q26",
        options: [{letter:"A",text:"$96,100"},{letter:"B",text:"$115,300"},{letter:"C",text:"$175,900"},{letter:"D",text:"$178,500"},{letter:"E",text:"$197,700"}],
        passage: "The following chart shows the average salary of politicians in selected countries in absolute terms (in thousands of dollars) and as a multiple of their country's gross domestic product (GDP) per person." },
      { displayNum: 14, tsaNum: 30, type: "Problem Solving", text: "What is the maximum number of major prizes which could be won?", correctAnswer: "C", hasWalkthrough: true,
        options: [{letter:"A",text:"7"},{letter:"B",text:"9"},{letter:"C",text:"10"},{letter:"D",text:"13"},{letter:"E",text:"14"}],
        passage: "In a prize draw, tickets are printed with 3-digit numbers from 001 to 999. Contestants pay to take a ticket at random. A major prize is awarded for all tickets where the product of the 3 digits on the ticket drawn is 8 and a minor prize is awarded when the product is 12. For example 143 wins a minor prize because 1 × 4 × 3 = 12." },
      { displayNum: 15, tsaNum: 31, type: "Problem Solving", text: "If she bought the same number of teas as coffees, what was the maximum number of hot drinks that Belle could have bought for the £32.00?", correctAnswer: "E", hasWalkthrough: true, figureKey: "tsa-q31",
        options: [{letter:"A",text:"9"},{letter:"B",text:"10"},{letter:"C",text:"12"},{letter:"D",text:"13"},{letter:"E",text:"14"}],
        passage: "The table shows the cost of hot drinks in a local café. Belle bought a number of hot drinks, including at least one of each tea, coffee and chocolate. She was charged £32.00." },
      { displayNum: 16, tsaNum: 32, type: "Problem Solving", text: "How many of the small cubes have one green face, one blue face, but no red face?", correctAnswer: "C", hasWalkthrough: true, figureKey: "tsa-q32",
        options: [{letter:"A",text:"6"},{letter:"B",text:"8"},{letter:"C",text:"12"},{letter:"D",text:"16"},{letter:"E",text:"24"}],
        passage: "I have a wooden cube with edges that are 5 cm long. I paint it in the following way: one pair of opposite faces is red, one pair of opposite faces is green, one pair of opposite faces is blue. Now I cut the cube into small cubes, each of whose edges are 1 cm long." },
      { displayNum: 17, tsaNum: 36, type: "Problem Solving", text: "Which one of the following statements is true?", correctAnswer: "E", hasWalkthrough: true, figureKey: "tsa-q36",
        options: [{letter:"A",text:"Harriet was given 'The Celebrated Six'."},{letter:"B",text:"Harriet was given 'Fly Away'."},{letter:"C",text:"Mehran was given 'The Biraffe'."},{letter:"D",text:"Miya was given 'Come Back'."},{letter:"E",text:"Miya was given 'Hungry Dinosaurs'."}],
        passage: "Grandma has spent £60 on five books which she is intending to give to her three grandchildren, Miya, Harriet and Mehran. She is going to give the books in a way that relates the cost to the time they normally spend reading (i.e. spend the most on the child who reads the most). Miya reads for an hour a day. Harriet reads for an hour a day on Monday to Thursday and 2 hours a day on Friday to Sunday. Mehran doesn't read on weekdays but does an hour and a half on each of Saturday and Sunday. The details of the books are shown in the table below." },
      { displayNum: 18, tsaNum: 37, type: "Problem Solving", text: "Which one of the following statements about the scoring system is the only one that is true?", correctAnswer: "C", hasWalkthrough: true,
        options: [{letter:"A",text:"A creamer is worth more points than a chop."},{letter:"B",text:"Two chops are worth less than three yips."},{letter:"C",text:"A glink is worth 2 points."},{letter:"D",text:"Three yips are worth more than three creamers."},{letter:"E",text:"A chop is worth 6 points."}],
        passage: "In a ball game points are accumulated by different combinations of four winning shots called a chop, a creamer, a glink and a yip. Playing the game for the first time, the only knowledge I have about the scoring system is that a chop is worth one point more than a creamer, and a creamer is worth twice as many points as a glink. I lose narrowly by 47 points to 50. I scored 3 chops, 4 yips, 3 creamers and 4 glinks. My victorious opponent scored 5 chops, 3 yips, 3 creamers and 2 glinks." },
      { displayNum: 19, tsaNum: 38, type: "Problem Solving", text: "Which one of the following shows a comparison of the numbers of cars in each category that were sold?", correctAnswer: "D", hasWalkthrough: true, figureKey: "tsa-q38",
        options: [{letter:"A",text:"bar 1"},{letter:"B",text:"bar 2"},{letter:"C",text:"bar 3"},{letter:"D",text:"bar 4"},{letter:"E",text:"bar 5"}],
        passage: "At the beginning of the day, a showroom had 32 vehicles for sale. The vehicles were advertised in five categories: hatchback, saloon, utility, estate car and people carrier. By the end of the day, 24 vehicles had been sold. The first chart shows a comparison of the numbers of vehicles in each category in the showroom at the beginning of the day, and the second chart shows a comparison of the numbers in the same categories in the showroom at the end of the day." },
      { displayNum: 20, tsaNum: 42, type: "Problem Solving", text: "What is the price of a bar of chocolate?", correctAnswer: "D", hasWalkthrough: true, figureKey: "tsa-q42",
        options: [{letter:"A",text:"15p"},{letter:"B",text:"25p"},{letter:"C",text:"30p"},{letter:"D",text:"55p"},{letter:"E",text:"60p"}],
        passage: "In my currency, there are six types of coin in circulation: 200p, 100p, 50p, 20p, 10p, 5p. I start with two coins. I visit a shop and purchase two bars of chocolate and pay using the two coins. My change consists of two coins. The next day I re-visit the shop and purchase another one bar of chocolate with that change. My new change, again, consists of two coins. The six coins I possess during these two days are all different. I only have two coins at any particular time. The price of a bar of chocolate does not change." },
      { displayNum: 21, tsaNum: 43, type: "Problem Solving", text: "What is the maximum number of points that could be scored when the next token is placed on the board?", correctAnswer: "E", hasWalkthrough: true, figureKey: "tsa-q43",
        options: [{letter:"A",text:"10"},{letter:"B",text:"11"},{letter:"C",text:"12"},{letter:"D",text:"13"},{letter:"E",text:"14"}],
        passage: "In a game, players take it in turns to place tokens onto squares of a grid. The squares on the grid are coloured white and grey. When a player places a token they score one point for every token on an adjacent square (either horizontally or vertically). For every adjacent square that is white an extra point is scored. The diagram below shows a position in one game. The number on each square shows the number of tokens currently placed on that square." },
      { displayNum: 22, tsaNum: 44, type: "Problem Solving", text: "It is my turn again and I know for certain that the two cards I am going to pick up will be a cat and mouse pair. Which two cards am I going to pick up?", correctAnswer: "D", hasWalkthrough: true, figureKey: "tsa-q44",
        options: [{letter:"A",text:"3 & 4"},{letter:"B",text:"3 & 6"},{letter:"C",text:"3 & 9"},{letter:"D",text:"3 & 12"},{letter:"E",text:"3 & 16"}],
        passage: "In Cat and Mouse, a game for two players, 16 cards are shuffled and then placed face down on a table. Cats are pictured on 8 of the cards and mice on the other 8. Both players pick up two cards at each turn. If the two cards are a cat and a mouse, the player keeps the cards and scores a point, but does not reveal which was the cat and which was the mouse. If the two cards are both cats or both mice, the player must put the cards back in the same places. My sister and I are currently playing a game, and I am leading by 3 points to 2." },
      { displayNum: 23, tsaNum: 46, type: "Problem Solving", text: "What is the lowest score that is not possible for a student to achieve?", correctAnswer: "C", hasWalkthrough: true, figureKey: "tsa-q46",
        options: [{letter:"A",text:"15"},{letter:"B",text:"22"},{letter:"C",text:"24"},{letter:"D",text:"27"},{letter:"E",text:"31"}],
        passage: "On Sports Day at St Jude's College points are awarded in each event as follows. Each student may enter a maximum of three events." },
      { displayNum: 24, tsaNum: 48, type: "Problem Solving", text: "I want to buy 1 bread roll, 1 apple and 1 chocolate bar. How much do I need to pay?", correctAnswer: "C", hasWalkthrough: true, figureKey: "tsa-q48",
        options: [{letter:"A",text:"$3.00"},{letter:"B",text:"$3.50"},{letter:"C",text:"$4.00"},{letter:"D",text:"$4.50"},{letter:"E",text:"$5.00"}],
        passage: "My three friends bought food at the supermarket. When I asked them, they did not remember the prices of the items, only the final amount they paid. Hector paid $3.50 for 3 bread rolls and 1 apple. Lee paid $8.00 for 1 apple and 4 chocolate bars. Olga paid $3.50 for 1 bread roll and 2 chocolate bars." },
      { displayNum: 25, tsaNum: 50, type: "Problem Solving", text: "One of the signs contains an error in one of the distances indicated. Which one of the signs contains the error?", correctAnswer: "D", hasWalkthrough: true, figureKey: "tsa-q50",
        options: [{letter:"A",text:"sign 1"},{letter:"B",text:"sign 2"},{letter:"C",text:"sign 3"},{letter:"D",text:"sign 4"},{letter:"E",text:"sign 5"}],
        passage: "There are five towns at various positions along a major ring road that encircles a city. Traffic travelling clockwise around the ring road is provided with information in the form of five 'distance' signs at various points along the road. The signs display the following information (all distances in km):" },
    ],
  },
};
